/*!40000 ALTER TABLE `quest_offer_reward` DISABLE KEYS */;
INSERT INTO `quest_offer_reward` VALUES (900131,0,0,0,0,0,0,0,0,'You made it. Good. Silverpine does not welcome strangers, but the road ahead begins here.',0),(900132,0,0,0,0,0,0,0,0,'The scout confirms it: these are not ordinary beasts. The keep is the source.',0),(900133,0,0,0,0,0,0,0,0,'A curse born from desperation. Remember that. It is a pattern we will see again.',0),(900134,0,0,0,0,0,0,0,0,'The keep waits. Gather your party, then speak with the Frostforge Guide when you are ready.',0),(900135,0,0,0,0,0,0,0,0,'Arugal is defeated, but the curse he unleashed will not vanish with him. Power called in desperation rarely leaves when the battle is over.',0),(900136,0,0,0,0,0,0,0,0,'You made it to the Zoram Strand. Good. The sea is never silent here.',0),(900137,0,0,0,0,0,0,0,0,'The shore confirms the danger. The ruins are active, and the cult is moving.',0),(900138,0,0,0,0,0,0,0,0,'The Twilight\'s Hammer hears something in the depths. That alone should worry us.',0),(900139,0,0,0,0,0,0,0,0,'The entrance waits. Gather your party and prepare to descend.',0),(900140,0,0,0,0,0,0,0,0,'Aku\'mai is defeated. But remember this: the deep places of Azeroth are rarely empty.',0),(900141,0,0,0,0,0,0,0,0,'Gnomeregan stands before us: a city of genius, ruin, and betrayal.',0),(900142,0,0,0,0,0,0,0,0,'The survivor reminds us that disasters are measured in people, not machines.',0),(900143,0,0,0,0,0,0,0,0,'Thermaplugg turned catastrophe into power. That ends now.',0),(900144,0,0,0,0,0,0,0,0,'Your party is ready. Enter Gnomeregan and face the traitor below.',0),(900145,0,0,0,0,0,0,0,0,'Thermaplugg has fallen. Gnomeregan is not restored, but justice has entered its halls.',0),(900146,0,0,0,0,0,0,0,0,'The Kraul stands before us. Remember: the quilboar are not merely monsters in the thorns. They are a people shaped by an ancient sacrifice and a harsh land.',0),(900147,0,0,0,0,0,0,0,0,'The messenger confirms what the roads already knew: fear has made the Barrens smaller for everyone.',0),(900148,0,0,0,0,0,0,0,0,'The captive confirms it. Charlga is not only leading the Kraul; she is binding it.',0),(900149,0,0,0,0,0,0,0,0,'The thorns await. Go carefully. A desperate people can be as dangerous as any demon.',0),(900150,0,0,0,0,0,0,0,0,'Charlga Razorflank is defeated. The Kraul remains, and so does the old pain beneath it. Not every wound in Azeroth can be solved by killing its ruler.',0),(900151,0,0,0,0,0,0,0,0,'Now you understand the wound beneath the Monastery. The Scarlet Crusade was not born from nothing. It was born from Lordaeron\'s grave.',0),(900152,0,0,0,0,0,0,0,0,'Thalnos is defeated. The Graveyard shows us the first truth: hatred of corruption does not protect anyone from becoming corrupted.',0),(900153,0,0,0,0,0,0,0,0,'Doan is defeated. The Library is quieter now, but the words written there have already shaped too many minds.',0),(900154,0,0,0,0,0,0,0,0,'Herod has fallen. The Crusade has lost one of its sharpened blades, but not the hand that forged him.',0),(900155,0,0,0,0,0,0,0,0,'Whitemane is defeated. The Monastery still stands, but its certainty has been wounded. Remember this: grief deserves compassion, but when grief becomes doctrine, it becomes dangerous.',0);
/*!40000 ALTER TABLE `quest_offer_reward` ENABLE KEYS */;
